import{_ as t,o as e,c as r,Q as a}from"./chunks/framework.b67c47e6.js";const b=JSON.parse('{"title":"QR Stickers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reports/qr_stickers/index.md","filePath":"guide/reports/qr_stickers/index.md","lastUpdated":1773939149000}'),o={name:"guide/reports/qr_stickers/index.md"},s=a('<h1 id="qr-stickers" tabindex="-1">QR Stickers <a class="header-anchor" href="#qr-stickers" aria-label="Permalink to &quot;QR Stickers&quot;">​</a></h1><p>The QR Stickers report generates printable QR code labels that can be attached to physical constructibles for quick identification on the shop floor.</p><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><ul><li><strong>Format:</strong> PDF</li><li><strong>Content:</strong> QR code labels with constructible identification info. Each QR code links to the constructible&#39;s Viewer page.</li></ul><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><table><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Paper size</strong></td><td>Choose the sticker layout (see formats below).</td></tr><tr><td><strong>Banner</strong></td><td>Optionally include a company banner image on the stickers.</td></tr></tbody></table><h2 id="paper-formats" tabindex="-1">Paper Formats <a class="header-anchor" href="#paper-formats" aria-label="Permalink to &quot;Paper Formats&quot;">​</a></h2><table><thead><tr><th>Format</th><th>Description</th></tr></thead><tbody><tr><td><strong>A4 — 4 QR codes</strong></td><td>Standard A4 page with 4 large QR stickers.</td></tr><tr><td><strong>A4 with banner — 4 QR codes</strong></td><td>A4 page with company banner and 4 QR stickers.</td></tr><tr><td><strong>A4 with banner — 12 QR codes</strong></td><td>A4 page with company banner and 12 smaller QR stickers.</td></tr><tr><td><strong>Dymo 159x104</strong></td><td>Sized for Dymo label printers (159mm x 104mm).</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The banner image is configured in <strong>Company Settings &gt; Styles</strong> under &quot;Sticker banner&quot;. Upload a wide logo or company header image there.</p></div><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p>Print QR stickers and attach them to assemblies or modules in the factory. Workers can scan the QR code with the produuz.it app or any QR reader to instantly open the Viewer for that constructible.</p>',11),n=[s];function i(d,c,h,l,p,u){return e(),r("div",null,n)}const g=t(o,[["render",i]]);export{b as __pageData,g as default};
